g.aria-label:
section A { assert sizeof(A) == 1280; ...}
section B { assert sizeof(B) == 1024; ...}
section C { assert sizeof(C) == 4096;
    set_sec 512; // pad initial 512 bytes of section C
    wr A;  // Write section A
    wr B;  // Write section B
    ...
}
output C, 32768; // absolute start is 0x8000
